using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Text.Json;
using LeightonSands;
using Microsoft.Xna.Framework;
using Microsoft.Xna.Framework.Content;
using Microsoft.Xna.Framework.Graphics;
using Microsoft.Xna.Framework.Input;

namespace LSUI;

public sealed class TitleScreen
{
    private const float CharacterTopRatio = 0.12f;
    private const float TitleTopRatio = 0.38f;
    private const float TitleWidthRatio = 1.35f;
    private const float TitleToButtonsGapRatio = 0.10f;
    private const float CharacterScaleMultiplier = 1.9f;
    private const float PreviewScaleMultiplier = 1.0f;

    private readonly JsonSerializerOptions _jsonOptions = new()
    {
        PropertyNameCaseInsensitive = true
    };

    private SpriteFont _uiFont = null!;
    private Texture2D _titleTexture = null!;
    private Texture2D _leftArrowTexture = null!;
    private Texture2D _rightArrowTexture = null!;
    private Texture2D _buttonTexture = null!;
    private GraphicsDevice _graphicsDevice = null!;
    private string _contentRootDirectory = "Content";
    private CharacterRegistry _characterRegistry = new();
    private CharacterDefinition? _selectedCharacter;
    private SpriteAnimation? _selectedIdleAnimation;
    private readonly Dictionary<string, SpriteAnimation?> _idleAnimations = new();
    private double _characterAnimTime;
    private KeyboardState _previousKeyboard;
    private int _selectedIndex;

    public void LoadContent(ContentManager content, GraphicsDevice graphicsDevice)
    {
        _graphicsDevice = graphicsDevice;
        _contentRootDirectory = content.RootDirectory;

        _uiFont = content.Load<SpriteFont>("Font/Main");
        _titleTexture = content.Load<Texture2D>("Textures/UI/titletext");
        _leftArrowTexture = content.Load<Texture2D>("Textures/UI/Buttons/left");
        _rightArrowTexture = content.Load<Texture2D>("Textures/UI/Buttons/right");
        _buttonTexture = content.Load<Texture2D>("Textures/UI/Buttons/button_main_3x1");

        LoadCharacters();
    }

    public void Update(GameTime gameTime)
    {
        _characterAnimTime += gameTime.ElapsedGameTime.TotalSeconds;

        var keyboard = Keyboard.GetState();
        if (WasPressed(keyboard, Keys.Left))
        {
            SelectPreviousCharacter();
        }

        if (WasPressed(keyboard, Keys.Right))
        {
            SelectNextCharacter();
        }

        if (keyboard.IsKeyDown(Keys.Enter) || keyboard.IsKeyDown(Keys.Space))
        {
            // TODO: transition to the first playable screen when it exists.
        }

        _previousKeyboard = keyboard;
    }

    public void Draw(SpriteBatch spriteBatch)
    {
        var viewport = _graphicsDevice.Viewport;
        var centerX = viewport.Width * 0.5f;

        var characterTop = viewport.Height * CharacterTopRatio;
        var titleScale = GetTitleScale(viewport.Width);
        var titleSize = new Vector2(_titleTexture.Width, _titleTexture.Height) * titleScale;
        var titleTop = viewport.Height * TitleTopRatio;
        var titlePosition = new Vector2(centerX - titleSize.X * 0.5f, titleTop);

        DrawCharacterSelect(spriteBatch, viewport, characterTop);
        spriteBatch.Draw(_titleTexture, titlePosition, null, Color.White, 0f, Vector2.Zero, titleScale, SpriteEffects.None, 0f);

        var buttonsTop = titlePosition.Y + titleSize.Y + viewport.Height * TitleToButtonsGapRatio;
        DrawMenuButtons(spriteBatch, viewport, buttonsTop);
    }

    private void DrawCharacterSelect(SpriteBatch spriteBatch, Viewport viewport, float topY)
    {
        if (_selectedIdleAnimation == null || _selectedCharacter == null)
        {
            return;
        }

        var anim = _selectedIdleAnimation;
        var frame = anim.GetFrame("forward", _characterAnimTime);
        var scale = MathHelper.Clamp(_selectedCharacter.Scale * CharacterScaleMultiplier, 0.1f, 4f);
        var frameSize = new Vector2(anim.FrameWidth, anim.FrameHeight) * scale;
        var centerX = viewport.Width * 0.5f;
        var spritePosition = new Vector2(centerX - frameSize.X * 0.5f, topY);

        spriteBatch.Draw(anim.Texture, spritePosition, frame, Color.White, 0f, Vector2.Zero, scale, SpriteEffects.None, 0f);

        var arrowSpacing = frameSize.X * 0.5f + 32f;
        var arrowScale = 1f;
        var leftPos = new Vector2(centerX - arrowSpacing - _leftArrowTexture.Width * arrowScale, topY + frameSize.Y * 0.35f);
        var rightPos = new Vector2(centerX + arrowSpacing, topY + frameSize.Y * 0.35f);
        var hasNeighbors = _characterRegistry.Characters.Count > 1;
        var arrowTint = hasNeighbors ? Color.White : new Color(120, 120, 120);

        if (hasNeighbors)
        {
            DrawNeighborPreview(spriteBatch, topY, centerX, -1, scale, frameSize, arrowScale);
            DrawNeighborPreview(spriteBatch, topY, centerX, 1, scale, frameSize, arrowScale);
        }

        spriteBatch.Draw(_leftArrowTexture, leftPos, null, arrowTint, 0f, Vector2.Zero, arrowScale, SpriteEffects.None, 0f);
        spriteBatch.Draw(_rightArrowTexture, rightPos, null, arrowTint, 0f, Vector2.Zero, arrowScale, SpriteEffects.None, 0f);
    }

    private void DrawNeighborPreview(
        SpriteBatch spriteBatch,
        float topY,
        float centerX,
        int direction,
        float baseScale,
        Vector2 mainFrameSize,
        float arrowScale)
    {
        var index = GetWrappedIndex(_selectedIndex + direction);
        var character = _characterRegistry.Characters[index];
        var anim = GetIdleAnimation(character);
        if (anim == null)
        {
            return;
        }

        var previewScale = baseScale * PreviewScaleMultiplier;
        var previewFrame = anim.GetFrame("forward", _characterAnimTime);
        var previewSize = new Vector2(anim.FrameWidth, anim.FrameHeight) * previewScale;
        var previewCenterOffset = (mainFrameSize.X * 0.5f) + _leftArrowTexture.Width * arrowScale + (previewSize.X * 0.5f) + 24f;
        var previewCenterX = centerX + previewCenterOffset * direction;
        var previewPos = new Vector2(previewCenterX - previewSize.X * 0.5f, topY + (mainFrameSize.Y - previewSize.Y) * 0.5f);
        var previewTint = new Color(255, 255, 255, 160);

        spriteBatch.Draw(anim.Texture, previewPos, previewFrame, previewTint, 0f, Vector2.Zero, previewScale, SpriteEffects.None, 0f);
    }

    private void DrawMenuButtons(SpriteBatch spriteBatch, Viewport viewport, float startY)
    {
        var buttonWidth = viewport.Width * 0.52f;
        var buttonHeight = viewport.Height * 0.14f;
        var gap = viewport.Height * 0.03f;
        var centerX = viewport.Width * 0.5f;
        var labels = new[] { "NEW GAME", "OPEN GAME", "SETTINGS" };

        for (var i = 0; i < labels.Length; i++)
        {
            var rect = new Rectangle(
                (int)(centerX - buttonWidth * 0.5f),
                (int)(startY + i * (buttonHeight + gap)),
                (int)buttonWidth,
                (int)buttonHeight);

            DrawButton(spriteBatch, rect, labels[i]);
        }
    }

    private void DrawButton(SpriteBatch spriteBatch, Rectangle rect, string label)
    {
        DrawButtonTexture(spriteBatch, rect);

        var textSize = _uiFont.MeasureString(label);
        var textPos = new Vector2(
            rect.X + (rect.Width - textSize.X) * 0.5f,
            rect.Y + (rect.Height - textSize.Y) * 0.5f);
        spriteBatch.DrawString(_uiFont, label, textPos, Color.White);
    }

    private void DrawButtonTexture(SpriteBatch spriteBatch, Rectangle rect)
    {
        var sliceWidth = _buttonTexture.Width / 3;
        var leftWidth = sliceWidth;
        var rightWidth = sliceWidth;
        var centerWidth = Math.Max(0, rect.Width - leftWidth - rightWidth);

        var sourceLeft = new Rectangle(0, 0, sliceWidth, _buttonTexture.Height);
        var sourceCenter = new Rectangle(sliceWidth, 0, sliceWidth, _buttonTexture.Height);
        var sourceRight = new Rectangle(sliceWidth * 2, 0, sliceWidth, _buttonTexture.Height);

        var destLeft = new Rectangle(rect.X, rect.Y, leftWidth, rect.Height);
        var destCenter = new Rectangle(rect.X + leftWidth, rect.Y, centerWidth, rect.Height);
        var destRight = new Rectangle(rect.Right - rightWidth, rect.Y, rightWidth, rect.Height);

        spriteBatch.Draw(_buttonTexture, destLeft, sourceLeft, Color.White);
        if (centerWidth > 0)
        {
            spriteBatch.Draw(_buttonTexture, destCenter, sourceCenter, Color.White);
        }
        spriteBatch.Draw(_buttonTexture, destRight, sourceRight, Color.White);
    }

    private void LoadCharacters()
    {
        var registryPath = GetContentPath("Characters/characters.json");
        if (!File.Exists(registryPath))
        {
            return;
        }

        var json = File.ReadAllText(registryPath);
        _characterRegistry = JsonSerializer.Deserialize<CharacterRegistry>(json, _jsonOptions) ?? new CharacterRegistry();
        var selectable = _characterRegistry.Characters.Where(character => character.Selectable).ToList();
        if (selectable.Count == 0)
        {
            return;
        }

        _characterRegistry.Characters = selectable;
        _idleAnimations.Clear();
        SelectCharacter(0);
    }

    private void SelectNextCharacter()
    {
        if (_characterRegistry.Characters.Count <= 1)
        {
            return;
        }

        var index = _characterRegistry.Characters.IndexOf(_selectedCharacter!);
        SelectCharacter((index + 1) % _characterRegistry.Characters.Count);
    }

    private void SelectPreviousCharacter()
    {
        if (_characterRegistry.Characters.Count <= 1)
        {
            return;
        }

        var index = _characterRegistry.Characters.IndexOf(_selectedCharacter!);
        var nextIndex = index - 1;
        if (nextIndex < 0)
        {
            nextIndex = _characterRegistry.Characters.Count - 1;
        }

        SelectCharacter(nextIndex);
    }

    private void SelectCharacter(int index)
    {
        if (index < 0 || index >= _characterRegistry.Characters.Count)
        {
            return;
        }

        _selectedIndex = index;
        _selectedCharacter = _characterRegistry.Characters[index];
        _characterAnimTime = 0;
        _selectedIdleAnimation = GetIdleAnimation(_selectedCharacter);
    }

    private int GetWrappedIndex(int index)
    {
        var count = _characterRegistry.Characters.Count;
        if (count == 0)
        {
            return 0;
        }

        var wrapped = index % count;
        return wrapped < 0 ? wrapped + count : wrapped;
    }

    private SpriteAnimation? GetIdleAnimation(CharacterDefinition character)
    {
        if (_idleAnimations.TryGetValue(character.Id, out var cached))
        {
            return cached;
        }

        var animation = LoadIdleAnimation(character);
        _idleAnimations[character.Id] = animation;
        return animation;
    }

    private SpriteAnimation? LoadIdleAnimation(CharacterDefinition character)
    {
        if (!character.Animations.TryGetValue("idle", out var animationPath))
        {
            return null;
        }

        var definitionPath = GetContentPath(Path.Combine("Characters", animationPath));
        if (!File.Exists(definitionPath))
        {
            return null;
        }

        var json = File.ReadAllText(definitionPath);
        var definition = JsonSerializer.Deserialize<AnimationDefinition>(json, _jsonOptions);
        if (definition == null || string.IsNullOrWhiteSpace(definition.Texture))
        {
            return null;
        }

        var texturePath = NormalizeTextureRelativePath(definition.Texture);
        var texture = LoadTextureFromContent(texturePath);
        if (texture == null)
        {
            return null;
        }

        return new SpriteAnimation(definition, texture);
    }

    private Texture2D? LoadTextureFromContent(string relativePath)
    {
        var texturePath = GetContentPath(relativePath);
        if (!File.Exists(texturePath))
        {
            return null;
        }

        using var stream = File.OpenRead(texturePath);
        return Texture2D.FromStream(_graphicsDevice, stream);
    }

    private string GetContentPath(string relativePath)
    {
        var safePath = relativePath.Replace('/', Path.DirectorySeparatorChar);
        return Path.Combine(AppContext.BaseDirectory, _contentRootDirectory, safePath);
    }

    private string NormalizeTextureRelativePath(string relativePath)
    {
        if (relativePath.StartsWith("Textures/", StringComparison.OrdinalIgnoreCase) ||
            relativePath.StartsWith("Textures\\", StringComparison.OrdinalIgnoreCase))
        {
            return relativePath;
        }

        return Path.Combine("Textures", relativePath);
    }

    private bool WasPressed(KeyboardState current, Keys key)
    {
        return current.IsKeyDown(key) && _previousKeyboard.IsKeyUp(key);
    }

    private float GetTitleScale(int viewportWidth)
    {
        if (_titleTexture.Width == 0)
        {
            return 1f;
        }

        var targetWidth = viewportWidth * TitleWidthRatio;
        var scale = targetWidth / _titleTexture.Width;
        return MathHelper.Clamp(scale, 0.1f, 3f);
    }
}

using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Text.Json;
using LeightonSands;
using Microsoft.Xna.Framework;
using Microsoft.Xna.Framework.Content;
using Microsoft.Xna.Framework.Graphics;
using Microsoft.Xna.Framework.Input;

namespace LSUI;

