    private const float TitleTopRatio = 0.38f;
    private const float TitleWidthRatio = 1.6f;
    private const float TitleToButtonsGapRatio = 0.10f;
    private const float CharacterScaleMultiplier = 1.9f;
    private const float PreviewScaleMultiplier = 1.0f;

    private readonly JsonSerializerOptions _jsonOptions = new()
    {
        PropertyNameCaseInsensitive = true
