        _titleTexture = content.Load<Texture2D>("Textures/UI/titletext");
        _leftArrowTexture = content.Load<Texture2D>("Textures/UI/Buttons/left");
        _rightArrowTexture = content.Load<Texture2D>("Textures/UI/Buttons/right");
