        }

        if (WasPressed(keyboard, Keys.Right))
        {
            SelectNextCharacter();
        }

        if (keyboard.IsKeyDown(Keys.Enter) || keyboard.IsKeyDown(Keys.Space))
        {
            // TODO: transition to the first playable screen when it exists.
        }

        _previousKeyboard = keyboard;
    }

