        var arrowTint = hasNeighbors ? Color.White : new Color(120, 120, 120);

        if (hasNeighbors)
        {
            DrawNeighborPreview(spriteBatch, topY, centerX, -1, scale, frameSize, arrowScale);
            DrawNeighborPreview(spriteBatch, topY, centerX, 1, scale, frameSize, arrowScale);
