        spriteBatch.Draw(_leftArrowTexture, leftPos, null, arrowTint, 0f, Vector2.Zero, arrowScale, SpriteEffects.None, 0f);
        spriteBatch.Draw(_rightArrowTexture, rightPos, null, arrowTint, 0f, Vector2.Zero, arrowScale, SpriteEffects.None, 0f);
    }

    private void DrawNeighborPreview(
        SpriteBatch spriteBatch,
        float topY,
        float centerX,
        int direction,
        float baseScale,
        Vector2 mainFrameSize,
