        var previewCenterX = centerX + previewCenterOffset * direction;
        var previewPos = new Vector2(previewCenterX - previewSize.X * 0.5f, topY + (mainFrameSize.Y - previewSize.Y) * 0.5f);
        var previewTint = new Color(255, 255, 255, 160);

        spriteBatch.Draw(anim.Texture, previewPos, previewFrame, previewTint, 0f, Vector2.Zero, previewScale, SpriteEffects.None, 0f);
    }

    private void DrawMenuButtons(SpriteBatch spriteBatch, Viewport viewport, float startY)
    {
        var buttonWidth = viewport.Width * 0.52f;
        var buttonHeight = viewport.Height * 0.14f;
        var gap = viewport.Height * 0.03f;
        var centerX = viewport.Width * 0.5f;
